selector_to_html = {"a[href=\"#typical-flow\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Typical flow<a class=\"headerlink\" href=\"#typical-flow\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#config\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Config<a class=\"headerlink\" href=\"#config\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">mbo</span> <span class=\"pre\">hpc</span> <span class=\"pre\">init</span></code> writes a commented <code class=\"docutils literal notranslate\"><span class=\"pre\">hpc.toml</span></code>. The four tables:</p>", "a[href=\"#shared-environment-mbo-server-configs\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Shared environment (<code class=\"docutils literal notranslate\"><span class=\"pre\">mbo_server_configs</span></code>)<a class=\"headerlink\" href=\"#shared-environment-mbo-server-configs\" title=\"Link to this heading\">#</a></h2><p>Separate from the <code class=\"docutils literal notranslate\"><span class=\"pre\">mbo</span> <span class=\"pre\">hpc</span></code> CLI above: the shared software under <code class=\"docutils literal notranslate\"><span class=\"pre\">/lustre/fs8/mbo/scratch/mbo_soft</span></code> (CLI tools, neovim, the <code class=\"docutils literal notranslate\"><span class=\"pre\">mbo</span></code> venv, repos) is exposed through <code class=\"docutils literal notranslate\"><span class=\"pre\">MBO_*</span></code> variables and navigation aliases. Source it once from <code class=\"docutils literal notranslate\"><span class=\"pre\">~/.bashrc</span></code>:</p>", "a[href=\"#modes\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modes<a class=\"headerlink\" href=\"#modes\" title=\"Link to this heading\">#</a></h2><p><strong><code class=\"docutils literal notranslate\"><span class=\"pre\">--mode</span> <span class=\"pre\">array</span></code> only helps across multiple nodes.</strong> On a single-node partition all tasks pile onto one node, where <code class=\"docutils literal notranslate\"><span class=\"pre\">cpus_per_task</span> <span class=\"pre\">\u00d7</span> <span class=\"pre\">tasks</span></code> must fit the node\u2019s CPUs and they share its GPUs \u2014 the same wall time as <code class=\"docutils literal notranslate\"><span class=\"pre\">single</span></code>. Use <code class=\"docutils literal notranslate\"><span class=\"pre\">mbo</span> <span class=\"pre\">hpc</span> <span class=\"pre\">info</span></code> to see a partition\u2019s <code class=\"docutils literal notranslate\"><span class=\"pre\">NODES</span></code> count, and <code class=\"docutils literal notranslate\"><span class=\"pre\">mbo</span> <span class=\"pre\">hpc</span> <span class=\"pre\">check</span> <span class=\"pre\">--mode</span> <span class=\"pre\">array</span></code> to catch the single-node case before submitting.</p>", "a[href=\"#hpc-slurm\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">HPC / SLURM<a class=\"headerlink\" href=\"#hpc-slurm\" title=\"Link to this heading\">#</a></h1><p>Run the LBM-Suite2p pipeline on a SLURM cluster (or locally) from a TOML config. Built on <a class=\"reference external\" href=\"https://github.com/facebookincubator/submitit\">submitit</a>.</p>", "a[href=\"#monitor\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Monitor<a class=\"headerlink\" href=\"#monitor\" title=\"Link to this heading\">#</a></h2><p>While <code class=\"docutils literal notranslate\"><span class=\"pre\">watch</span></code> follows a terminal: <code class=\"docutils literal notranslate\"><span class=\"pre\">o</span></code>/<code class=\"docutils literal notranslate\"><span class=\"pre\">e</span></code> switch out/err, <code class=\"docutils literal notranslate\"><span class=\"pre\">n</span></code>/<code class=\"docutils literal notranslate\"><span class=\"pre\">p</span></code> switch task logs, <code class=\"docutils literal notranslate\"><span class=\"pre\">q</span></code> quits.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
